<template>
  <div id="app">
    <div class="roww">
      <div class="leftv">
        <nav-component/>
      </div>
      <div class="rightv">
       
        <transition name="fade"> 
          <router-view />
        </transition>
      </div>
    </div>
 <quick-menu :menu-count=count :icon-class=icons :menu-url-list=list :position=position :background-color=backgroundColor :is-open-new-tab=isOpenNewTab></quick-menu>

  </div>
</template>

<script>
import Nav from './components/main/Nav.vue'
import quickMenu from 'vue-quick-menu';



export default {
  name: 'App',
  components: {
    "nav-component": Nav,
    'quick-menu' :quickMenu
  },
   data(){
      return {
        count:4,
        icons:["fa fa-facebook-f","fa fa-twitter","fa fa-instagram","fa fa-youtube-play"],
        list:["https://www.facebook.com/Iglesia-de-Cristo-en-Elgin-243271119073381/","https://twitter.com/CristoElgin","https://www.instagram.com/cristoelgin/","https://www.youtube.com/user/TheCatch13777/featured"],
        backgroundColor:'#222',
        color:'#ffffff',
        position:'bottom-right',
        isOpenNewTab:true
      }
  },
  methods: {
       afterEnter: function( el ) {
      // how to have this per-route
      console.log( 'Route entered' );
    }
  }
}
</script>

<style lang="scss">
@import './assets/main';
// @import "https://cdn.jsdelivr.net/npm/animate.css@3.5.1";

body { margin: 0; background: #222}

.fade-enter-active, .fade-leave-active {
  transition-property: opacity;
  transition-duration: .25s;
}

.fade-enter-active {
  transition-delay: .25s;
}

.fade-enter, .fade-leave-active {
  opacity: 0
}

#app {
  font-weight:300;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  color: #2c3e50;
  width: 100%;
}
  .roww {
    display: flex;

    .leftv {
      float: left;
      width: 120px;
      
    }
    .rightv {
      float: left;
      width: 100%;
      // margin-left: 100px;
      // padding-left: 50px; // MOVE WHOLE DIV
      height: 100vh;
      background-color: #222;
      }
  }

  li {
    list-style: none;
  }

  // .menu {
  //   bottom: -15px;
  //   right: 15px;
  // }
  .quick-menu {
      margin-bottom: 15px;
      margin-right: -15px;
      z-index: 99999;
    
  }

 .menu .core-menu {
    background-color: #222;
    border-radius: 50%;
    margin-bottom: 10px;
  }


  @media screen and (max-width: 748px) {

    body {    height: 100vh!important; }

    #app {
   
    }

    .leftv {
      float: left;
      width: 0px!important;
      
    }
    .rightv {
      float: left;
      width: 100%;
      // margin-left: 100px;
      // padding-left: 50px; // MOVE WHOLE DIV
      height: 100vh;
      background-color: #222;
      }

  }


  

</style>



