<template>
<div style="position: fixed; z-index: 99;">
     <div class="side-menu .visible-xs" @click="toggleSidemenu()"><div id="nav-icon1"><span></span><span></span><span></span></div></div>
    <div class="wrapper">
         <transition name="slide-right">
    <nav id="sidebar">
            <img class="logo" src="../../assets/img/NewLogo-01.svg" alt="">
                    <!-- <h4 style="padding:35px 0 0 15px;">Iglesia de Cristo</h4> -->
                <ul class="list-unstyled components">
                    <li class="active">
                        <router-link to="/" data-toggle="collapse" aria-expanded="false">
                             <img class="icon" src="../../assets/img/icons/house2.svg" alt="" >
                            <h4>Home</h4> 
                        </router-link>
                    </li>
                    
                    <li>
                        <router-link to="/crecimiento">
                             <img class="icon" src="../../assets/img/icons/head.svg" alt="">
                            <h4>Crecimiento</h4>
                        </router-link>
                    </li>
                    <li>
                        <router-link to="/calendario">
                             <img class="icon" src="../../assets/img/icons/calendar.svg" alt="">
                            <h4>Calendario</h4>
                        </router-link>
                    </li>
                    <li>
                        <router-link to="/gallery">
                             <img class="icon" src="../../assets/img/icons/gallery.svg" alt="">
                            <h4>Fotos</h4>
                        </router-link>
                    </li>
                      <li>
                        <router-link to="/donar">
                             <img class="icon" src="../../assets/img/icons/give.svg" alt="" >
                            <h4>Donar</h4>
                        </router-link>
                    </li>
                     <li>
                        <router-link to="/Location">
                             <img class="icon" src="../../assets/img/icons/location.svg" alt="" >
                            <h4>Direcciones</h4>
                        </router-link>
                    </li>
                    <li>
                        <router-link to="/contact">
                             <img class="icon" src="../../assets/img/icons/email.svg" alt="">
                            <h4>Contacto</h4>
                        </router-link>
                    </li>
                   <li>
                        <router-link to="/member">
                             <img class="icon" src="../../assets/img/icons/member.svg" alt="" >
                            <h4>Miembros</h4>
                        </router-link>
                    </li>
                    <!-- <li v-if="userStore.authUser !== null && userStore.authUser.access_token">
                        <router-link to="/member/dashboard">
                             <img class="icon" src="../../assets/img/icons/member.svg" alt="" style="width:45px; margin-left:5px;">
                            <h4>Miembros</h4>
                        </router-link>
                    </li> -->
                </ul>

            </nav>
         
            <span class="divider hidden-xs"></span>
            </transition>
        <!-- <div id="content">
             <div class="navbar-header">
                            <button type="button" id="sidebarCollapse" class="navbar-btn active">
                                <span></span>
                                <span></span>
                                <span></span>
                            </button>
                    </div>
            </div> -->
    </div>
     <!-- <quick-menu :menu-count=count :icon-class=icons :menu-url-list=list :position=position :background-color=backgroundColor :is-open-new-tab=isOpenNewTab></quick-menu> -->
     </div>
</template>

<script>
export default {
  name: 'Nav',
  data(){
      return {
      
      }
  },
  methods: {
      toggleSidemenu(){
                $('#sidebar').toggleClass("show");
                $('.icon').toggleClass("show-icons");
                $('.logo').toggleClass("show-logo");
 
      },
      toggleButton(){
              $('#nav-icon1').click(function(){
            $('#nav-icon1').toggleClass('open');
            });
      }
     
  },

  mounted(){
    //    this.toggleSidemenu();
      this.toggleButton();
     
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main';
@import '../../assets/bootstrap.min';

.divider {
    position: relative;
    top: 0vh;
    left: -4px;
    height: 110vh;
    width: 7px;
    opacity: .9;
    background: $gradient-2;
}

img.logo {
    width: 80px;
    padding: 30px 0 15px 20px;

}


h4 {
    display: inline;
    display: none;
    opacity: 0;
    font-size: 16px;
    position: fixed;
    font-weight: 300;
    padding: 0px 0 0 30px;
}

.wrapper {
    display: flex;
    align-items: stretch;
}

#sidebar {
    transition: all 0.3s;
    width: 120px;
    height: 110vh;
    background: #3f4146;
    // background: $gradient-2-light

    ul {
        margin: 0;
        li {
            padding: 1vh 0 2vh 0px;
       .icon {
            width: 40px;
            left: 0;
        }  
        .icon:hover {
            transform: scale(1.1);
      }
     }
    }
}

    .side-menu {
        display: none;
      position: fixed;
      z-index: 999;
      margin: 0px 0 0 10px;
      transform: scale(.7);
    }

@media screen and (min-width: 800px) {

    #sidebar:hover {
      width: 250px;
    //   background: $gradient-2;
    background: #535458;
      
      h4{
          display: inline;
          opacity: .8;
          font-size: 1.3em;
          margin: 0px;
          color:white;
      }   
}
 }


@media screen and (max-width: 748px) {

    .show {
        width: 120px!important;
    }

    .show-icons {
         width: 40px!important;
    }
    .show-logo {
         width: 90px!important;
    }

    #sidebar {
    transition: all 0.3s;
    width: 0px;
    height: 110vh;
    background: #3f4146;

    img.logo {
        position: relative;
    width: 0px;
    left: 45%;
    margin-right: -50%;
    transform: translate(-50%, -50%);
    top:70px;

      h4{
          display: inline;
          opacity: .8;
          font-size: 1.3em;
          margin: 0px;
          color:white;
      }  
    

}

    ul {
        margin-top: 50px;
        li {
            padding: 1vh 0 3vh 0px;
            
       .icon {
           transition: all 0.3s;
            width: 0px;
            left: 0;
        }  
        .icon:hover {
            transform: scale(1.1);
      }
     }
    }
}


    .side-menu {
      display: block;
      position: fixed;
      z-index: 999;
      margin: 0px 0 0 10px;
    }


}




</style>



