            <ul class="nav">
              <li><a href="#intro" @click="scrollIntoView"><span>Intro</span></a></li>
              <li><a href="#welcome" @click="scrollIntoView"><span>Welcome</span></a></li>
              <li><a href="#evang" @click="scrollIntoView"><span>Evangelio</span></a></li>
