    <scrollactive class="my-nav" ref="scrollactive" :offset="0"
      :duration="800"
      bezier-easing-value=".5,0,.35,1">
      <a href="#intro" class="scrollactive-item">Intro</a>
      <a href="#welcome" class="scrollactive-item">Acerca</a>
      <a href="#topics" class="scrollactive-item">Horario</a>
