  </scrollactive>
  </div>
</template>

<script>

export default {
  name: 'scrollspy'
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main';


// fixed side navigation with dots
.my-nav{
  position: fixed;
  height: 35px;
  bottom:0px;
  width: 100%;
  z-index: 9;
  text-align: center;
  transition: all .3s;
  background: rgba(87, 86, 86, 0.885);


  a{
    text-decoration: none;
    font-size: 1vw;
    color: white;
    padding-right: 10vw;
    
  }
  a:hover {
    font-weight: 500;
  }

  .is-active {
    font-weight: 700;
    background: $gradient-2;
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-size: 100px;
    line-height: 35px;
}
  
}

.my-nav:hover {

}

</style>



