<template>
  <div class="container">
     <div class="row">
        <div class="col col-sm-6 col-xs-12"> <v-calendar :attributes='attrs' is-single-paned  is-expanded> </v-calendar></div>
        <div class="col col-sm-6 col-xs-12"> <div class="header">Eventos</div>
            <div id="events">
            </div>
            <div class="slideshow-container boxshadow">
                <div class="mySlides fading"  v-for="months in events.months" v-if="months.month !== null" v-show="months.id == currentMonth">
                        <h3>{{months.month}}</h3>
                    <div class="DateDiv boxshadow" v-for="event in months.event" @click="clickedEvent(event); showingModal = true;">
                        <h4>{{event.name}}</h4>
                        <span>{{event.date}}</span>
                        <span class="DateRange">{{event.month}}</span>
                    </div> 
                </div>
            </div>
            <transition name="slide-fade">
               <div class="modall" id="addModal" v-if="showingModal" >
                <div class="modalContainer">
                    <div class="modalHeading">
                        <div class="close" @click="showingModal = false;">
                            &times;
                        </div>
                        <div class="modalContent">
                            <h4 v-model="eventClicked.name">{{eventClicked.name}}</h4>
                        </div>
                    </div>
                </div>
            </div>
            </transition>
        </div>
     </div>
</div> 
</template>

<script>
import json from '../assets/events/events.json';

export default {
  name: 'Events',
  data() {
    return {
         attrs: [
            {
            key: 'Cantos',
            dates: { weekdays: [2] },
            highlight: {
                backgroundColor: '#ff8080',
                
            },
            // Just use a normal style
            contentStyle: {
                color: '#fafafa',
            },
            contentHoverStyle: {
                color: 'blue'
            },
            // Our new popover here
            popover: {
                label: 'Cantos! 7-8PM',
            }
            },
            {
                key: 'Estudio',
                dates: {weekdays: [4]},
                highlight: {
                    backgroundColor: 'blue'
                },
            // Just use a normal style
            contentStyle: {
                color: '#fafafa',
            },
            contentHoverStyle: {
                color: '#222'
            },
            // Our new popover here
            popover: {
                label: 'Estudio! 7-8PM',
            }
            },
            // {
            //     key: 'salida',
            //     dates: [new Date(2018, 0, 12)],
            //     highlight: {
            //         backgroundColor: 'yellow',
            // } 
            // }
      ],
      events: {
          months:[]
      },
      currentMonth: "",
      eventClicked: {},
      showingModal: false
    }
  },
   methods: {
      getEvents(){

            this.events.months = json;           

            var d = new Date();
            var m = d.getMonth();
            var slideIndex = m + 1;

            this.currentMonth = slideIndex - 1;

            showSlides(slideIndex);   

            $(".c-arrow-layout .vc-angle-right").click(function(){
                   showSlides(slideIndex += 1);
                })

             $(".c-arrow-layout .vc-angle-left").click(function(){
                   showSlides(slideIndex -= 1);
                })

            function currentSlide(n) {
            showSlides(slideIndex = n);
            }
            function showSlides(n) {
            var i;
            var slides = document.getElementsByClassName("mySlides");
            if (n > slides.length) {slideIndex}      
            if (n < 1) {slideIndex}
            for (i = 0; i < slides.length; i++) {
                $(slides[i]).hide();
                
            }

            $(slides[slideIndex-1]).show();

            }
            
      },
      clickedEvent(event){
          this.eventClicked = event;
          console.log("event clicked")
          console.log(event);
      }
  },
  mounted(){
      this.getEvents();
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../assets/main';
@import '../assets/bootstrap.min';


.header {
    text-align: center;
}

.slideshow-container {
    height: 95%;

    .mySlides{

    }
}

.eventMonth {
    height: 100%;
    position: absolute;
}


.container {
    margin-top: 100px;
}
.c-pane-container {
    position: relative;
    width: 100%!important;
    height: 70vh;

}
    .c-day{
        height: 9vh!important;
    }

    .c-day-content{
        border-radius: 0px!important;
    }

    .DateDiv {

        padding: 10px 0 10px 20px;
        margin: 15px;
        background: $gradient-2;
        border-radius: 10px;
        color: white;
        cursor: pointer;
        span {
            font-style: italic;
            font-size: 12px;
            float: right;
            padding: 5px 10px;
        }
        .DateRange {
            display:none;
        }
    }

    /* Fading animation */
.fading{
  -webkit-animation-name: fading;
  -webkit-animation-duration: 1.8s;
  animation-name: fading;
  animation-duration: 1.8s;
}

@-webkit-keyframes fading {
  from {opacity: .4} 
  to {opacity: 1}
}

@keyframes fading {
  from {opacity: .4} 
  to {opacity: 1}
}


.modall {
    position: fixed;
    top: 0;
    left: 0;
    bottom: 0;
    right: 0;
    
    .modalContainer {
       width: 70vw;
       background: transparent;
        margin: auto;
        margin-top: 100px;
    }

    .modalHeading {
        padding: 6px;
        background: $gradient-2;
        color: white;
        border-radius: 5px;
    }

    .modalContent {
        min-height: 435px;
        padding: 44px;
        margin: 10px;
        background: rgba(0, 0, 0, 0.253);
    }

    .close {
        padding: 10px 16px 0 0;
        color: white;
        font-size: 38px;
        
    }
    .close:hover {
        transform: scale(1.4);
        transition: all .5s;
    }
}


</style>



