<template>
  <div>
      <div class="sections">
         <div class="section-left">
              <router-link to="/crecimiento/himnos">
            <div class="section boxshadow">
                 <i class="fa fa-music"></i>
            </div>
              </router-link>
      </div>
      <div class="divider"></div>
      <div class=" section-right">
           <router-link to="/crecimiento/estudios">
          <div class="section boxshadow">
                  <i class="fa fa-microphone"></i>
          </div>
           </router-link>
      </div>  
      </div>
     
      
  </div>
</template>

<script>
export default {
  name: 'Study'
  
}
</script>


<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../assets/main';
@import '../assets/bootstrap.min';

.divider {
    position: absolute;
    height: 100vh;
    width: 30px;
    left: 50vw;
    opacity: .9;
    // border-radius: 10px;
    background: $gradient-2;
    // transition: all .7s;
}
.sections {
    width: 98vw;
}
.section-left {
    width: 50%;
    height: 100vh;
    float: left;

       div {
        background: $gradient-2;  
        position: relative;
        top:50vh;
        left: 50%; 
        width: 10vw;
        height: 10vw;
        border-radius: 50%;
        margin-right: -50%;
        transform: translate(-50%, -50%);  
         transition: all .5s;   
    }

    .fa-music {
        position: relative;
        color:white;
        font-size: 5vw;
        margin-right: -50%;
        transform: translate(-50%, -50%);  
        left: 50%;
        top: 50%;
        transition: all .5s;
        cursor: pointer;
    }
 
 
    div:hover {
        background: $gradient-2;
        transition: all .5s;
        height: 100vh;
        width: 50vw;
        border-radius: 0%;
        .fa-music 
        {
            font-size: 8vw;
            transition: all .5s;
            color: #222;
        
        }
    }
}

    .section-right {
        width: 50%;
        height: 100vh;
        float: left;
        position: relative;
    
        div {
            background: $gradient-2;  
            position: relative;
            top:50vh;
            left: 50%;
            width: 10vw;
            height: 10vw;
            border-radius: 50%;
            margin-right: -50%;
            transform: translate(-50%, -50%);  
             transition: all .5s;    
        }

        
    .fa-microphone {
        position: relative;
        color:white;
        font-size: 5vw;
        margin-right: -50%;
        transform: translate(-50%, -50%);  
        left: 50%;
         top: 50%;
         transition: all .5s;
         cursor: pointer;
     
    }
            div:hover {
        background: $gradient-2;
        transition: all .5s;
        height: 100vh;
        width: 49vw;
        border-radius: 0%;

        .fa-microphone 
        {
            font-size: 8vw;
            transition: all .5s;
            color: #222;
            
        }
    }
    }

</style>



