<template>
  <div >
      <div class="group left col-sm-6"><img src="../../assets/img/texts/groupleft.png" alt=""></div>
      <div class="group right col-sm-6">
        <h2 class="indent">En la Iglesia de Cristo en Elgin puedes encontrar various groupos de todas la diferentes edades. Cada ministerio se mantiene activos con actividades, convivencia y ense&ntilde;ansa mensuales.</h2>
       
        <ul>
          <li>Congregacion</li>
           <div class="divider"></div>
          <li>Varones</li>
           <div class="divider"></div>
          <li>Mujeres</li>
           <div class="divider"></div>
          <li>Jovenes</li>
           <div class="divider"></div>
          <li>Ni&ntilde;os</li>
           <div class="divider"></div>
          <li>Ancianos</li>
           <div class="divider"></div>
        </ul>
      </div>
     
  </div>
</template>

<script>
export default {
  name: 'groups'
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main';
@import '../../assets/bootstrap.min';

.group {
    height: 100vh;
}
.left {
  background: $gradient-2;

  img {
    width: 100%;
    top:0px;
  }
}
.right {
  background: white;
  h2 {
    font-weight: 300;
    padding: 30px;
    
  }
  ul {
    padding: 0px 0 0 0;
  }

  li {
    padding: 10px 0px;
    font-size: 3vh;
    text-align: center;
  }
}

.divider {
    position: relative;
    height: 6px;
    width: 50%;
    left: 25%;
    opacity: .9;
    border-radius: 10px;
    background: $gradient-2;
    transition: all .7s;
}


</style>



