<template>
  <div id="series">
       <div class="loader"></div>
       <div class="cont">
         <div id="content"> 
             <track-controls/>
            <br>
            <div id="songs">        
                <input type="text" id="myInput" placeholder="Search for names.." title="Type in a name">
                <div id="showSongs">

                </div>
            </div>    


      <div id="mylist" class="list">
          
             <div v-for="serie in data.series">
                        <h1 class="hd" >{{serie.series_name}}</h1>
                    <div class="pllist">
                            <li v-for="audio in serie.audio" :value="audio.url"> {{audio.name}} </li>
                       
                    </div>
             </div>
      </div>
       
         </div>

         <player-controls/>
       </div>
  </div>
</template>

<script>

import json from '../../assets/audio/audio.json';
import playercontrols from './player-controls.vue';
import trackcontrols from './track-controls.vue';

export default {
  name: 'series',
  components: {
      "player-controls": playercontrols,
      "track-controls": trackcontrols
  },
  data(){
      return {
          data: ""
      }
  },
methods: {

     pageLoader(){
        //  $(window).load(function(){
        //         $('.loader').fadeOut();
        //     });

         setTimeout(function () {
                $(".cont").show("slow")
                $(".loader").hide("slow")
            }, 2000);

     },   
     getData: function(){ 

            this.data = json;
        
        
          this.$http.get('https://cors-anywhere.herokuapp.com/http://iglesiadecristoenelgin.com/Test/audioapi.php').then(response => {

              var audio,input, dir, ext, elementVal, elementPrev, elementNext, elementTxt, curtrack, playbtn, pausebtn, mutebtn, mutebtnon, prevbtn, nextbtn, searchinput, seekslider, volumeslider, seeking, seekto, curtimetext, durtimetext, $this;
                    dir = "https://archive.org/download/mythium/";
                    ext = ".mp3";
                    input = this.search

           

                 //set object references
                    curtrack = document.getElementById("curtrack");
                    playbtn = document.getElementById("playbtn");
                    pausebtn = document.getElementById("pausebtn");
                    mutebtn = document.getElementById("mutebtn");
                    mutebtnon = document.getElementById("mutebtnon");                    
                    seekslider = document.getElementById("seekslider");
                    volumeslider = document.getElementById("volumeslider");
                    curtimetext = document.getElementById("curtimetext");
	                durtimetext = document.getElementById("durtimetext");
	                prevbtn = document.getElementById("prevbtn");
                    nextbtn = document.getElementById("nextbtn");
                    searchinput = document.getElementById("myInput");
                
                audio = new Audio();

                    $('.pllist').hide();
                    $('#showSongs').hide();  

                        $('.hd').click(function(){
                            
                            $(this).next(".pllist").slideToggle('slow');
                      
                        });

                        $("#myInput").keyup(function(){
                    
                            $(".pllist").show();
                            $('#showSongs').show();  


                            if(!this.value){
                                $(".pllist").hide();
                                $('#showSongs').hide();  

                            }

                        });
                         

                        $("#mylist li, #showSongs li").click(function (){
                        
                            $this = $(this);
                        
                            elementVal =  $(this).attr('value');
                            elementPrev =  $(this).prev().attr('value');
                            elementNext = $(this).next().attr('value');
                        
                            elementTxt = $(this).html();
                            
                            audio.src = dir + elementVal + ext;
                            audio.play();                           
                
                            $(playbtn).addClass("hide");
                            $(pausebtn).removeClass("hide");
                            
                            seekslider.value = 0; 
                            
                            curtrack.innerHTML = elementTxt;

                        });
            //event listening
                        $(pausebtn).click(function () {
                        
                        if(audio.play) {
                            audio.pause();
                             $(playbtn).removeClass("hide");
                             $(pausebtn).addClass("hide");

                        } else {
                            audio.play();
                             $(playbtn).addClass("hide");
                             $(pausebtn).removeClass("hide");

                        }
                        });
                        $(playbtn).click(function () {
                        
                        if(audio.pause) {
                            audio.play();
                             $(playbtn).addClass("hide");
                             $(pausebtn).removeClass("hide");

                        } else {
                            audio.pause();
                             $(playbtn).removeClass("hide");
                             $(pausebtn).addClass("hide");

                        }
                            
                        });
                        $(mutebtn).click(function () {
                            if(audio.muted) {
                            audio.muted = false;
                            $(mutebtnon).addClass("hide");
                            $(mutebtn).removeClass("hide")

                        } else {
                            audio.muted = true;
                            $(mutebtnon).removeClass("hide")
                            $(mutebtn).addClass("hide")
                            
                        }
                            
                        })

                         $(mutebtnon).click(function () {
                            if(audio.muted) {
                            audio.muted = false;
                            $(mutebtn).removeClass("hide")
                            $(mutebtnon).addClass("hide")
                            
                        } else {
                            audio.muted = true;
                            $(mutebtn).addClass("hide")
                            $(mutebtnon).removeClass("hide")
                            
                        }
                            
                        })

                        $(prevbtn).click(function () {
                                if(elementPrev !== undefined) {
                            audio.src = dir + elementPrev + ext ;
                            audio.play();
                        } else {
                            audio.src = audio.src;
                            audio.play();
                        }
                            
                        })
                        $(nextbtn).click(function () {
                                   if(elementNext !== undefined){
                            audio.src = dir + elementNext + ext ;
                            audio.play();
                        } else {
                            audio.src = audio.src;
                            audio.play();
                        }
                            
                        })
                        // $("#app a").click(function (){
                        //     audio.pause();
                        // })
                        $(seekslider).mousedown(function (event) {
                            seeking = true; 
                            seek(event);
                        })
                        $(seekslider).mousemove(function (event) {
                            seek(event);
                        })
                        $(seekslider).mouseup(function () {
                            seeking = false;
                        })
                        $(volumeslider).mousemove(function () {
                            setVolume();
                        })
                        audio.addEventListener("timeupdate", function(){ seektimeupdate()});
                        
                        $(searchinput).keyup(function (){
                            searchFunction();
                        }) 

                     function seek(event){
                        if(seeking){
                            seekslider.value = event.clientX - seekslider.offsetLeft;
                            seekto = audio.duration * (seekslider.value / 100);
	                        audio.currentTime = seekto;
                        }
                    }
             /////////////////////////////////////////////
                    function setVolume(){
                        audio.volume = volumeslider.value / 100;
                    }
          ////////////////////////////////////////////////
                    function seektimeupdate(){
                        var nt = audio.currentTime * (100 / audio.duration);
                        seekslider.value = nt;
                        var curmins = Math.floor(audio.currentTime / 60);
                        var cursecs = Math.floor(audio.currentTime - curmins * 60);
                        var durmins = Math.floor(audio.duration / 60);
                        var dursecs = Math.floor(audio.duration - durmins * 60);
                    
                        
                            if(cursecs < 10){ cursecs = "0"+cursecs; }
                            if(dursecs < 10){ dursecs = "0"+dursecs; }
                            if(curmins < 10){ curmins = "0"+curmins; }
                            if(durmins < 10){ durmins = "0"+durmins; }
                        curtimetext.innerHTML = curmins+":"+cursecs;
                        durtimetext.innerHTML = durmins+":"+dursecs;
                    }
                    
                function searchFunction(){

                
                 var filter, showSongs, lisongs, div, li, h1, i, a;

                    filter = searchinput.value.toUpperCase();
                    div = document.getElementById("mylist");
                    showSongs = document.getElementById("showSongs");
                    li = div.getElementsByTagName("li");  
                    lisongs = showSongs.getElementsByTagName("li");  
                    h1 = div.getElementsByTagName("h1"); 

                   
         
               for (i = 0; i < li.length; i++) {
                      a = li[i];
                  
                    if (a.innerHTML.toUpperCase().indexOf(filter) > -1 ) {
                        li[i].style.display = "";
                        $(a).addClass("display");
                    } 
                    else {
                        li[i].style.display = "none";
                        $(a).removeClass("display");
                }
            }
             for (i = 0; i < lisongs.length; i++) {
                      a = lisongs[i];
                  
                    if (a.innerHTML.toUpperCase().indexOf(filter) > -1 ) {
                        lisongs[i].style.display = "";
                        $(a).addClass("display");
                    } 
                    else {
                        lisongs[i].style.display = "none";
                        $(a).removeClass("display");
                }
            }
        }
      })       
     }
    },
    mounted(){
      this.getData();
      this.pageLoader();
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main';
@import '../../assets/bootstrap.min';


.hide {
    display: none;
}



#series {
    // background: $gradient-2;
    height: 100vh;
    top: 0;
    padding-top: 3%;
    padding-left: 5%;
    position: relative;
    .cont {
        display: none;
    }

   
}
    .hd {
        color: white;
    }

    .pllist {

        li {
            color:white;
        }
    }

</style>



