<template>
  <div id="social-media">
      <div class="container social-icons">
          <div class="row icon-container">
              <div class="col-sm-3"><a class="icons" href="https://www.facebook.com/Iglesia-de-Cristo-en-Elgin-243271119073381/" target="blank"><i class="fa fa-7x fa-facebook-f"></i>
                    <h1 >
                         <!-- {{facebookLikes}} likes -->
                           <i-count-up
                                :startVal="0"
                                :endVal= facebookLikes 
                                :decimals="0"
                                :duration="2" 
                                :options="options" 
                                  @ready="onReady"
                                ></i-count-up> Likes
                    </h1></a></div>
              <div class="col-sm-3"><a class="icons" href="https://twitter.com/CristoElgin" target="blank"><i class="fa fa-7x fa-twitter"></i>
              <h1 >
                  <i-count-up
                                :startVal="0"
                                :endVal= twitterFollowers 
                                :decimals="0"
                                :duration="2" 
                                :options="options" 
                                  @ready="onReady"
                                ></i-count-up> followers
                  </h1></a></div>
              <div class="col-sm-3"><a class="icons" href="https://www.instagram.com/cristoelgin/" target="blank"><i class="fa fa-7x fa-instagram" aria-hidden="true"></i>
              <h1>
                  <i-count-up
                                :startVal="0"
                                :endVal= instagramFollowers
                                :decimals="0"
                                :duration="2" 
                                :options="options" 
                                  @ready="onReady"
                                ></i-count-up> followers
                                </h1></a></div>
              <div class="col-sm-3"><a class="icons" href="https://www.youtube.com/user/TheCatch13777/featured" target="blank"><i class="fa fa-7x fa-youtube-play"></i>
              <h1 >
                  <i-count-up
                                :startVal="0"
                                :endVal= youtubeViews
                                :decimals="0"
                                :duration="2" 
                                :options="options" 
                                  @ready="onReady"
                                ></i-count-up> views
                  </h1></a></div>
          </div>
      </div>
  </div>
</template>

<script>
import ICountUp from 'vue-countup-v2'

export default {
  name: 'social-media',
  components: {
      ICountUp
  },
  data(){
      return {
          youtubeViews: "",
          facebookLikes: "",
          twitterFollowers: "",
          instagramFollowers: "",
          options: {
            useEasing: true,
            useGrouping: true,
            separator: ',',
            decimal: '.',
            prefix: '',
            suffix: ''
          }  
          
      }
  },
  methods: {
        onReady: function(instance, CountUp) {
        const that = this;
        instance.update(that.endVal + 100);
      },
    getYoutube: function(){
        
      this.$http.get("https://cors-anywhere.herokuapp.com/https://www.youtube.com/user/TheCatch13777/about").then(response => {
                    var text = response.body;

                    var result = text.substring(text.lastIndexOf("viewCountText")+33, text.lastIndexOf("bold")-3);

                    this.youtubeViews = result.replace(",", '');

                 

      }) ;
    },
    getFacebook: function(){
        this.$http.get("https://cors-anywhere.herokuapp.com/https://www.facebook.com/plugins/page.php?href=https%3A%2F%2Fwww.facebook.com%2FIglesia-de-Cristo-en-Elgin-243271119073381%2F&tabs&width=340&height=130&small_header=false&adapt_container_width=false&hide_cover=false&show_facepile=false&appId=555207491508441").then(response => {
                    var text = response.body;

                    var result = text.substring(text.lastIndexOf("_1drq")+33, text.lastIndexOf("likes"));
                    
                    this.facebookLikes = result;

      }) ;
    },
    getTwitter: function(){
         this.$http.get("https://cors-anywhere.herokuapp.com/https://twitter.com/CristoElgin?ref_src=twsrc%5Etfw").then(response => {
                    var text = response.body;

                    var result = text.substring(text.lastIndexOf("followers_count&quot;:")+22, text.lastIndexOf(",&quot;friends_count&quot;:"));
              
                    this.twitterFollowers = result;

                       console.log(text)

      }) ;
    },
    getInsta: function(){
        this.$http.get("https://cors-anywhere.herokuapp.com/https://www.instagram.com/cristoelgin/").then(response => {
                            var text = response.body;

                            var result = text.substring(text.lastIndexOf("meta content=")+14, text.lastIndexOf("og:type")-10);

                            var lastresult = result.substring(result.lastIndexOf("meta content="), result.lastIndexOf("Followers"));
                        
                    
                            this.instagramFollowers = lastresult;
                
            }) ;
    }

  },
  mounted(){
      this.getYoutube();
      this.getFacebook();
      this.getTwitter();
      this.getInsta();
      
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main';
@import '../../assets/bootstrap.min';

#social-media {
    height: 55vh;
    background-image: url('../../assets/img/@like.png');
    background-size: 100%;
    

    .social-icons {
        position: relative;
        top: 15vh;
        // left: 0px;
        padding-left: 10vw;

        .fa-7x {
            font-size: 7vw;
        }

        .fa-facebook-f {
            color: rgb(42, 95, 194);
              transition: all .5s;
        }
        .fa-twitter {
            color: rgb(31, 169, 244);
              transition: all .5s;
        }
        .fa-youtube-play {
            color: rgb(226, 55, 55);
              transition: all .5s;
        }
        .fa-instagram {
            color: #fff;
              transition: all .5s;
              background: linear-gradient( #400080, transparent), linear-gradient(200deg, #d047d1, #ff0000,#ffff00);             
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;    
            }  

        h1 {
            margin-left: -45px;
            color: #fff;
            font-weight: 200;
        }
        
     }

     a:hover {
         text-decoration: none;
     }

    .fa-facebook-f:hover, .fa-twitter:hover, .fa-youtube-play:hover, .fa-instagram:hover {
        transition: all .5s;
        transform: scale(1.4);
    }
}


@media screen and (max-width: 748px) {

    #social-media {
        height: 100vh;
         background-image: url('../../assets/img/@like-mobile.png');
        background-size: 45%;
        background-position: -30px 40px;
        background-repeat: no-repeat;
    }

    .icon-container {
        position: relative;
        padding-left: 60px;
        width: 100%;
    }
     .social-icons {

         padding: 15% 0; 
      
      .fa-7x {
            font-size: 10vw!important;
            padding-top: 40px;
            padding-right: 15px;
        }

     }
     
}

   h1 {
       display: inline;
       margin: 10px!important;
        }



  

    

</style>



